parameters.jsCode:
return [
  {
    json: {
      enabled: true,
      name: 'BBC News',
      url: 'https://www.bbc.com/news',
      language: 'en',
      article_url_pattern: '^https://www\\.bbc\\.com/news/articles/[a-z0-9]+$',
      topics: ['breaking']
    }
  },
  {
    json: {
      enabled: true,
      name: 'Al Jazeera',
      url: 'https://www.aljazeera.com/news/',
      language: 'en',
      article_url_pattern: '^https://www\\.aljazeera\\.com/news/\\d{4}/\\d{1,2}/\\d{1,2}/[a-z0-9-]+$',
      topics: ['breaking']
    }
  }
].filter(i => i.json.enabled);

const crypto = require('crypto');
const fp = u => crypto.createHash('sha256').update(u).digest('hex').slice(0, 16);
const out = [];
for (const item of $input.all()) {
  const links = item.json?.data?.links || [];
  const source = $('Source list').itemMatching(item.pairedItem.item).json;
  const re = new RegExp(source.article_url_pattern);
  const seen = new Set();
  for (const u of links) {
    if (re.test(u) && !seen.has(u)) {
      seen.add(u);
      out.push({
        json: {
          source_name: source.name,
          source_url: source.url,
          language: source.language,
          topics: source.topics,
          article_url: u,
          fingerprint: fp(u)
        }
      });
      if (seen.size >= 5) break;
    }
  }
}
return out;

const cachedFps = new Set($input.all().map(i => i.json.fingerprint).filter(Boolean));
const allUrls = $('Filter article URLs').all();
const newArticles = allUrls.filter(i => !cachedFps.has(i.json.fingerprint));
if (newArticles.length === 0) {
  // All cached - output a sentinel so Per article Done branch still fires
  return [{ json: { _all_cached: true } }];
}
return newArticles;

parameters.jsonBody:
={
  "url": "{{$json.article_url}}",
  "formats": [{
    "type": "json",
    "prompt": "Extract this news article for a 60-second audio bulletin. Return fields: headline (<=90 chars, plain text), dek (1 sentence), body (180-220 words, plain spoken prose for TTS — no URLs, no markdown, expand abbreviations), published_date (ISO), source (publisher)."
  }],
  "onlyMainContent": true
}

