const q = s => s == null ? 'NULL' : `'${String(s).replace(/'/g, "''")}'`;
const qa = arr => `'{${(arr || []).map(v => String(v).replace(/'/g, "''")).join(',')}}'`;
const out = [];
for (const item of $input.all()) {
  const j = item.json?.data?.json || {};
  const ctx = $('Per article').itemMatching(item.pairedItem.item).json;
  if (!j.headline || !j.body) continue;
  const fingerprint = require('crypto').createHash('sha256').update(ctx.article_url).digest('hex').slice(0, 16);
  const scraped_at = new Date().toISOString();
  const insert_sql = `INSERT INTO news_items (fingerprint, source_name, article_url, language, headline, dek, body, published_date, topics, scraped_at) VALUES (${q(fingerprint)}, ${q(ctx.source_name)}, ${q(ctx.article_url)}, ${q(ctx.language)}, ${q(j.headline)}, ${q(j.dek)}, ${q(j.body)}, ${q(j.published_date)}, ${qa(ctx.topics)}, ${q(scraped_at)}) ON CONFLICT (fingerprint) DO NOTHING`;
  out.push({ json: { fingerprint, source_name: ctx.source_name, article_url: ctx.article_url, language: ctx.language, headline: j.headline, dek: j.dek || null, body: j.body, insert_sql } });
}
return out;

const item = $('Shape for DB').first().json;
const userMsg = ['Headline: ', item.headline, String.fromCharCode(10), String.fromCharCode(10), 'Content: ', item.body].join('');
const payload = {
  messages: [
    { role: 'system', content: 'You are a world-class broadcast news scriptwriter. Rewrite the following article into a 220-word spoken-prose paragraph for a news anchor. Use a neutral, professional tone. No markdown, no bullet points, no URLs. Expand all abbreviations. Ensure it flows naturally for audio consumption.' },
    { role: 'user', content: userMsg }
  ],
  temperature: 0.7
};
return [{ json: { ...item, llm_payload: payload } }];

