const items = $input.all();
const summaries = items.map(i => i.json.llm_summary).filter(Boolean);
const sources = [...new Set(items.map(i => i.json.source_name))];
const script = summaries.join('

---

');

const targetLang = 'English';
const code = 'en';
const systemPrompt = `You are an expert podcast scriptwriter for a lively, 2-person daily news podcast. Assemble the provided article summaries into a continuous conversational flow. The final script MUST be in ${targetLang}. Format the output precisely for a Text-to-Speech engine. Use clear speaker labels ("Joe:" and "Jane:") and include inline audio tags to direct the delivery.

### DIRECTOR'S NOTES
Style: Upbeat, positive, engaging, and explicitly inviting. The podcast must capture and keep the attention of listeners with a low attention span.
Dynamics: High-speed delivery with fluid transitions — no dead air.
Pacing: Fast and punchy.
Accent: Use a native, natural ${targetLang} accent for both speakers. If English, Joe is an enthusiastic London DJ and Jane has a bright, Southern California accent.
Tags: Use inline tags like [excitedly], [laughs], [bored], [whispers], [reluctantly], [sighs], [gasp], [very fast] to add emotion and variation to the delivery. Please use the English versions of these tags even for non-English scripts, as required by the TTS engine.

Ensure the conversation flows naturally and accurately conveys the news facts. Include a catchy intro and a warm outro. Total length: 600-900 words.`;

const episode_sql_template = `INSERT INTO episodes (language, script, source_names) VALUES (${q(code)}, '{{SCRIPT_PLACEHOLDER}}', '{${sources.map(s => s.replace(/'/g, "''")).join(',')}}') RETURNING id`;
const llm_payload = { messages: [ { role: 'system', content: systemPrompt }, { role: 'user', content: `Here are ${summaries.length} article summaries (translate and adapt them to ${targetLang} natively):

${script}` } ], temperature: 0.7 };

return [{ json: { summaries, sources, language: code, article_count: summaries.length, episode_sql_template, llm_payload } }];

